  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// User model - Admin, Manager, User roles\nmodel User {\n  id       String   @id @default(cuid())\n  email    String   @unique\n  password String\n  phone    String?\n  fullName String\n  role     UserRole @default(USER)\n\n  // Relations\n  vehicles      Vehicle[]\n  bookings      Booking[]\n  payments      Payment[]\n  monthlyPasses MonthlyPass[]\n  adminLogs     AdminLog[]    @relation(\"AdminLogs\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nenum UserRole {\n  ADMIN\n  MANAGER\n  USER\n}\n\n// Vehicle model - stores customer's vehicles\nmodel Vehicle {\n  id          String      @id @default(cuid())\n  userId      String\n  plateNumber String      @unique\n  vehicleType VehicleType\n  color       String?\n\n  // Relations\n  user           User            @relation(fields: [userId], references: [id], onDelete: Cascade)\n  bookings       Booking[]\n  parkingRecords ParkingRecord[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId])\n}\n\nenum VehicleType {\n  CAR\n  MOTORBIKE\n}\n\n// ParkingLot model - parking facility information\nmodel ParkingLot {\n  id         String  @id @default(cuid())\n  name       String\n  address    String\n  totalSlots Int\n  zones      Json? // stores zone configuration: { carZones: [...], motoZones: [...] }\n  hourlyRate Decimal @db.Decimal(10, 2)\n\n  // Relations\n  slots          ParkingSlot[]\n  bookings       Booking[]\n  parkingRecords ParkingRecord[]\n  monthlyPasses  MonthlyPass[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ParkingSlot model - individual parking spaces\nmodel ParkingSlot {\n  id           String      @id @default(cuid())\n  parkingLotId String\n  zoneId       String\n  slotNumber   String\n  vehicleType  VehicleType\n  status       SlotStatus  @default(AVAILABLE)\n\n  // Relations\n  parkingLot     ParkingLot      @relation(fields: [parkingLotId], references: [id], onDelete: Cascade)\n  bookings       Booking[]\n  parkingRecords ParkingRecord[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([parkingLotId, slotNumber])\n  @@index([parkingLotId])\n  @@index([status])\n}\n\nenum SlotStatus {\n  AVAILABLE\n  OCCUPIED\n  RESERVED\n  MAINTENANCE\n}\n\n// Booking model - customer parking reservations\nmodel Booking {\n  id            String        @id @default(cuid())\n  userId        String\n  vehicleId     String\n  parkingSlotId String\n  parkingLotId  String\n  startTime     DateTime\n  endTime       DateTime?\n  estimatedCost Decimal       @db.Decimal(10, 2)\n  status        BookingStatus @default(PENDING)\n\n  // Relations\n  user          User           @relation(fields: [userId], references: [id], onDelete: Cascade)\n  vehicle       Vehicle        @relation(fields: [vehicleId], references: [id], onDelete: Cascade)\n  parkingSlot   ParkingSlot    @relation(fields: [parkingSlotId], references: [id], onDelete: Cascade)\n  parkingLot    ParkingLot     @relation(fields: [parkingLotId], references: [id], onDelete: Cascade)\n  payment       Payment?\n  parkingRecord ParkingRecord? @relation(fields: [parkingRecordId], references: [id])\n\n  createdAt       DateTime @default(now())\n  updatedAt       DateTime @updatedAt\n  parkingRecordId String?\n\n  @@index([userId])\n  @@index([vehicleId])\n  @@index([parkingSlotId])\n  @@index([status])\n}\n\nenum BookingStatus {\n  PENDING // waiting for confirmation\n  CONFIRMED // slot is reserved\n  COMPLETED // parking finished\n  CANCELLED // cancelled by user\n}\n\n// ParkingRecord model - actual vehicle entry/exit logs\nmodel ParkingRecord {\n  id            String        @id @default(cuid())\n  vehicleId     String\n  parkingLotId  String\n  parkingSlotId String\n  bookingId     String?\n  checkIn       DateTime\n  checkOut      DateTime?\n  actualCost    Decimal       @default(0) @db.Decimal(10, 2)\n  paymentStatus PaymentStatus @default(PENDING)\n\n  // Relations\n  vehicle     Vehicle     @relation(fields: [vehicleId], references: [id], onDelete: Cascade)\n  parkingLot  ParkingLot  @relation(fields: [parkingLotId], references: [id], onDelete: Cascade)\n  parkingSlot ParkingSlot @relation(fields: [parkingSlotId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n  bookings  Booking[]\n\n  @@index([vehicleId])\n  @@index([parkingLotId])\n  @@index([checkIn])\n}\n\n// Payment model - payment transactions\nmodel Payment {\n  id            String        @id @default(cuid())\n  userId        String\n  bookingId     String?       @unique\n  monthlyPassId String?       @unique\n  amount        Decimal       @db.Decimal(10, 2)\n  method        PaymentMethod\n  status        PaymentStatus @default(PENDING)\n  referenceId   String? // transaction ID from payment gateway\n\n  // Relations\n  user        User         @relation(fields: [userId], references: [id], onDelete: Cascade)\n  booking     Booking?     @relation(fields: [bookingId], references: [id], onDelete: SetNull)\n  monthlyPass MonthlyPass? @relation(fields: [monthlyPassId], references: [id], onDelete: SetNull)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId])\n  @@index([status])\n}\n\nenum PaymentMethod {\n  CASH\n  CARD\n  MOMO\n  VNPAY\n}\n\nenum PaymentStatus {\n  PENDING\n  SUCCESS\n  FAILED\n  REFUNDED\n}\n\n// MonthlyPass model - monthly parking subscription\nmodel MonthlyPass {\n  id           String      @id @default(cuid())\n  userId       String\n  parkingLotId String\n  vehicleType  VehicleType\n  startDate    DateTime\n  endDate      DateTime\n  price        Decimal     @db.Decimal(10, 2)\n  status       PassStatus  @default(ACTIVE)\n\n  // Relations\n  user       User       @relation(fields: [userId], references: [id], onDelete: Cascade)\n  parkingLot ParkingLot @relation(fields: [parkingLotId], references: [id], onDelete: Cascade)\n  payment    Payment?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId])\n  @@index([parkingLotId])\n  @@index([status])\n}\n\nenum PassStatus {\n  ACTIVE\n  EXPIRED\n  CANCELLED\n}\n\n// AdminLog model - audit trail for admin actions\nmodel AdminLog {\n  id           String  @id @default(cuid())\n  adminId      String\n  action       String // CREATE, UPDATE, DELETE, etc.\n  resourceType String // User, ParkingLot, Booking, etc.\n  resourceId   String?\n  changes      Json? // { old: {...}, new: {...} }\n  ipAddress    String?\n\n  // Relations\n  admin User @relation(\"AdminLogs\", fields: [adminId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n\n  @@index([adminId])\n  @@index([resourceType])\n}\n",
